function solve(nums) {
    const n = nums.length;
    let maxSum = -Infinity;

    // Precompute prefix sums for quick range sum calculation
    const prefixSum = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    // Precompute left increasing segments
    const leftInc = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 0;
        }
    }

    // Precompute right increasing segments
    const rightInc = new Array(n).fill(0);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 0;
        }
    }

    // Precompute left decreasing segments (from p to q)
    const leftDec = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        if (nums[i] < nums[i - 1]) {
            leftDec[i] = leftDec[i - 1] + 1;
        } else {
            leftDec[i] = 0;
        }
    }

    // Iterate all possible p and q
    for (let p = 1; p < n - 2; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check if nums[l..p] is strictly increasing (l is p - leftInc[p])
            const l = p - leftInc[p];
            if (l < 0 || leftInc[p] < 1) continue;

            // Check if nums[p..q] is strictly decreasing (leftDec[q] >= q - p)
            if (leftDec[q] < q - p) continue;

            // Check if nums[q..r] is strictly increasing (r is q + rightInc[q])
            const r = q + rightInc[q];
            if (r >= n || rightInc[q] < 1) continue;

            // Calculate the sum from l to r
            const currentSum = prefixSum[r + 1] - prefixSum[l];
            if (currentSum > maxSum) {
